select 
from t_r_approval_record


        AND status = #{status}



        AND (

            created_by = #{userId}

            OR project_code IN (SELECT code FROM t_r_project WHERE created_by = #{userId})


                OR workspace_id = #{workspaceId}

        )


order by created_at desc

select 
from t_r_approval_record
where resource_type = #{resourceType}
  and resource_code = #{resourceCode}
order by created_at desc

mapper.update:
update t_r_approval_record
set current_stage = #{newStage}
where id = #{id}
  and status = 'PENDING'
  and current_stage = #{oldStage}

update t_r_approval_record
set status = #{status},
    resolved_at = #{resolvedAt}
where id = #{id}
  and status = 'PENDING'

update t_r_approval_record
set status = 'WITHDRAWN',
    withdrawn_at = #{withdrawnAt},
    withdrawn_reason = #{withdrawnReason}
where id = #{id}
  and status = 'PENDING'
  and created_by = #{ownerId}
